"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[212],{831:(e,t,i)=>{i.d(t,{o:()=>o,s:()=>l});var n=i(5155),a=i(2115);let s=(0,a.createContext)(null),r={fa:{site:{title:"سورین صنعت فرزان | واردات تجهیزات برق صنعتی",description:"واردات و صادرات تجهیزات برق صنعتی، اتوماسیون، ابزار دقیق"},nav:{logo:"سورین صنعت فرزان",links:[{label:"خانه",href:"/"},{label:"درباره ما",href:"/about"},{label:"خدمات",href:"/services"},{label:"محصولات",href:"/products"},{label:"وبلاگ",href:"/blog"},{label:"تماس",href:"/contact"},{label:"سوالات",href:"/faq"}],contactLabel:"تماس با ما"},hero:{name:"سورین صنعت فرزان",subtitle:"تامین‌کننده معتبر تجهیزات برق صنعتی، اتوماسیون و ابزار دقیق در ایران و منطقه",cta:"مشاوره رایگان"},brands:{label:"برندها",title:"نمایندگی برندهای معتبر جهانی",items:[{name:"Siemens",img:"/images/brands/siemens.svg"},{name:"Schneider Electric",img:"/images/brands/schneider.svg"},{name:"ABB",img:"/images/brands/abb.svg"},{name:"Delta",img:"/images/brands/delta.svg"},{name:"Omron",img:"/images/brands/omron.svg"},{name:"Mitsubishi",img:"/images/brands/mitsubishi.svg"}]},gallery:{label:"گالری",title:"پروژه‌ها و تجهیزات",items:[{img:"https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/gallery/g1.jpg",title:"تابلو برق فشار قوی",cat:"پروژه"},{img:"https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/gallery/g2.jpg",title:"اتاق کنترل صنعتی",cat:"پروژه"},{img:"https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/gallery/g3.jpg",title:"خط تولید اتوماتیک",cat:"پروژه"},{img:"https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/gallery/g4.jpg",title:"تجهیزات ابزار دقیق",cat:"تجهیزات"},{img:"https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/gallery/g5.jpg",title:"سیستم مانیتورینگ",cat:"تجهیزات"},{img:"https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/gallery/g6.jpg",title:"مرکز مهندسی",cat:"اداری"}]},about:{label:"درباره ما",title:"پیشرو در تامین تجهیزات برق صنعتی",description:"شرکت سورین صنعت فرزان با بیش از ۷ سال تجربه در زمینه واردات و صادرات تجهیزات برق صنعتی، اتوماسیون، ابزار دقیق و محصولات الکتریکی، یکی از معتبرترین تامین‌کنندگان صنایع در ایران و منطقه می‌باشد. با تیمی مجرب شامل ۵۲ نفر پرسنل متخصص، خدمات مهندسی، مشاوره، طراحی، اجرا و تامین تجهیزات را به صنایع مختلف ارائه می‌دهیم.",images:["https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/about/office.jpg","https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/about/team.jpg","https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/about/warehouse.jpg","https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/about/project.jpg"],stats:[{value:"۷+",label:"سال تجربه"},{value:"۵۲+",label:"نیروی متخصص"},{value:"۹۸٪",label:"رضایت مشتریان"},{value:"۱۲+",label:"کشور هدف"}]},services:{label:"خدمات",title:"خدمات تخصصی مهندسی",items:[{icon:"PenTool",title:"طراحی، مشاوره و اجرا",desc:"طراحی، مشاوره فنی و اجرای پروژه‌های برق و اتوماسیون صنعتی از صفر تا صد با جدیدترین استانداردهای جهانی"},{icon:"Monitor",title:"مانیتورینگ و شبکه",desc:"طراحی و پیاده‌سازی سیستم‌های مانیتورینگ، شبکه‌های ارتباطی صنعتی و کنترل متمرکز فرآیندهای تولیدی"},{icon:"Cpu",title:"پشتیبانی قطعات",desc:"ارائه پیشنهادات فنی به‌روز برای قطعات قدیمی، تامین قطعات جایگزین و مشاوره فنی تخصصی"},{icon:"Wrench",title:"تامین تجهیزات",desc:"واردات و تامین انواع تجهیزات برق صنعتی، اتوماسیون، ابزار دقیق و قطعات یدکی از برندهای معتبر جهانی"}]},products:{label:"محصولات",title:"محصولات و تجهیزات",desc:"تامین انواع تجهیزات برق صنعتی، اتوماسیون، ابزار دقیق و کابل‌ها از معتبرترین برندهای جهانی",items:[{slug:"electrical-equipment",title:"تجهیزات برق صنعتی",cat:"کلیدها، کنتاکتورها، فیوز، رله",img:"/images/products/p1.jpg",desc_detail:"انواع تجهیزات برق صنعتی از برندهای معتبر جهانی شامل کلیدهای اتوماتیک، کنتاکتور، فیوز، رله‌های حفاظتی، ترانسفورماتورهای جریان و ولتاژ. تمامی محصولات دارای استانداردهای IEC و NEMA بوده و با گارانتی معتبر عرضه می‌شوند."},{slug:"industrial-automation",title:"اتوماسیون صنعتی",cat:"PLC زیمنس، دلتا، HMI، درایو VFD",img:"/images/products/p2.jpg",desc_detail:"تامین و پشتیبانی انواع PLCهای زیمنس S7-1200 و S7-1500، PLCهای دلتا سری DVP، HMI، درایوهای فرکانس متغیر (VFD)، و نرم‌افزارهای مرتبط. همراه با خدمات برنامه‌نویسی و راه‌اندازی."},{slug:"power-plant",title:"تجهیزات نیروگاهی",cat:"دیزل ژنراتور، UPS، ترانسفورماتور",img:"/images/products/p3.jpg",desc_detail:"تجهیزات نیروگاهی و برق صنعتی شامل دیزل ژنراتورهای آماده به کار، سیستم‌های UPS، ترانسفورماتورهای توزیع و قدرت، و تابلوهای توزیع برق فشار قوی و ضعیف."},{slug:"instrumentation",title:"ابزار دقیق",cat:"فشارسنج، دما سنج، فلو متر",img:"/images/products/p4.jpg",desc_detail:"انواع تجهیزات ابزار دقیق شامل ترانسمیتر فشار و دما، فلو مترهای صنعتی، سطح سنج‌ها، آنالایزرهای گاز، و کالیبراتورهای دقیق از برندهای معتبر جهانی."},{slug:"industrial-cables",title:"کابل و سیم صنعتی",cat:"کابل‌های برق، ابزار دقیق، شبکه",img:"/images/products/p5.jpg",desc_detail:"انواع کابل‌های برق فشار ضعیف و متوسط، کابل‌های ابزار دقیق، کابل‌های شبکه صنعتی، و کابل‌های فیبر نوری منطبق با استانداردهای بین‌المللی."},{slug:"switchboards",title:"تابلو برق",cat:"تابلوهای فشار قوی و ضعیف، کنترل",img:"/images/products/p6.jpg",desc_detail:"طراحی و ساخت انواع تابلوهای برق فشار قوی و ضعیف، تابلوهای کنترل و مانیتورینگ، تابلوهای توزیع برق، و تابلوهای MCC مطابق با استانداردهای IEC و با بالاترین کیفیت."}],cta:"مشاهده همه محصولات"},testimonials:{label:"مشتریان",title:"نظرات مشتریان",items:[{quote:"همکاری با سورین صنعت فرزان در تامین تجهیزات اتوماسیون پروژه‌های ما، کیفیت و زمان‌بندی تحویل عالی را به همراه داشته است.",author:"مهندس رضا محمدی",role:"مدیر پروژه",company:"صنایع برق پارس"},{quote:"تیم حرفه‌ای سورین در تامین تجهیزات تابلو برق و ابزار دقیق بسیار دقیق و به‌موقع عمل می‌کنند.",author:"دکتر سمیرا احمدی",role:"مدیر تامین",company:"پترو صنعت شرق"},{quote:"خدمات مشاوره فنی و پشتیبانی قطعات سورین صنعت فرزان در بهینه‌سازی خط تولید ما نقش موثری داشته است.",author:"مهندس علی کاظمی",role:"مدیر فنی",company:"کابل‌سازی غرب"}]},contact:{label:"تماس",title:"با ما در ارتباط باشید",subtitle:"برای استعلام قیمت، مشاوره تخصصی و همکاری",form:{name:"نام و نام خانوادگی",email:"ایمیل",phone:"شماره تماس",message:"پیام شما",submit:"ارسال پیام",success:"پیام شما با موفقیت ارسال شد."},info:{address:"تهران، جنت‌آباد مرکزی",phone:"۰۲۱۲۲۲۰۱۷۳۴",email:"info@surinsf.com",hours:"شنبه - چهارشنبه ۸-۱۷ | پنجشنبه ۸-۱۳"}},faq:{label:"سوالات",title:"سوالات متداول",items:[{q:"آیا محصولات شما ضمانت اصالت دارند؟",a:"بله، تمامی محصولات دارای ضمانت اصالت کالا و گارانتی معتبر از نمایندگی‌های رسمی می‌باشند."},{q:"مدت زمان تحویل سفارشات چقدر است؟",a:"محصولات موجود در انبار تهران طی ۱-۳ روز و سفارشات وارداتی بین ۲-۶ هفته تحویل داده می‌شوند."},{q:"آیا مشاوره فنی رایگان دارید؟",a:"بله، تیم مهندسی ما آماده ارائه مشاوره فنی رایگان برای انتخاب تجهیزات مناسب پروژه شما می‌باشد."},{q:"روش‌های پرداخت چگونه است؟",a:"پرداخت به صورت واریز بانکی، چک و برای پروژه‌های بزرگ به صورت اعتباری با قرارداد رسمی امکان‌پذیر است."},{q:"چه برندهایی را نمایندگی می‌کنید؟",a:"برندهای زیمنس، اشنایدر الکتریک، ABB، دلتا، Omron و بسیاری دیگر."}]},blog:{label:"وبلاگ",title:"آخرین مطالب و مقالات",desc:"مطالب تخصصی در حوزه برق صنعتی، اتوماسیون و ابزار دقیق",articles:[{slug:"plc-selection-guide",title:"راهنمای جامع انتخاب PLC صنعتی",excerpt:"بررسی انواع PLCهای موجود در بازار و نکات مهم در انتخاب مناسب‌ترین گزینه برای خط تولید شما",content:"انتخاب PLC مناسب یکی از مهم‌ترین تصمیمات در طراحی و اجرای پروژه‌های اتوماسیون صنعتی است. در این مقاله به بررسی انواع PLCهای موجود در بازار از برندهای معتبری مانند زیمنس، دلتا، ABB و Omron می‌پردازیم.\n\nعوامل مهم در انتخاب PLC شامل تعداد ورودی/خروجی‌ها، نوع پروتکل‌های ارتباطی، شرایط محیطی، و بودجه پروژه می‌باشد. PLCهای زیمنس سری S7-1200 برای پروژه‌های کوچک تا متوسط و سری S7-1500 برای پروژه‌های بزرگ مناسب هستند.\n\nدلتا الکترونیکس نیز با PLCهای سری DVP گزینه‌های مقرون به صرفه‌ای با قابلیت‌های پیشرفته ارائه می‌دهد.",date:"۱۴۰۴/۰۳/۱۵",cat:"اتوماسیون",img:"https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/blog/plc.jpg"},{slug:"industrial-iot",title:"اتوماسیون صنعتی و اینترنت اشیاء",excerpt:"تحول دیجیتال در صنعت با ترکیب اتوماسیون سنتی و فناوری‌های نوین IIoT",content:"انقلاب صنعتی چهارم با ترکیب اتوماسیون صنعتی سنتی و اینترنت اشیاء (IoT) تحولی شگرف در صنعت ایجاد کرده است. IIoT یا اینترنت اشیاء صنعتی به اتصال ماشین‌آلات، سنسورها و سیستم‌های کنترلی از طریق شبکه اینترنت گفته می‌شود.\n\nمزایای IIoT شامل مانیتورینگ لحظه‌ای خط تولید، نگهداری پیش‌بینی‌کننده، بهینه‌سازی مصرف انرژی، و افزایش بهره‌وری کلی تجهیزات (OEE) می‌باشد.\n\nشرکت سورین صنعت فرزان با بهره‌گیری از تیم مهندسی مجرب، راه‌حل‌های جامع IIoT از مشاوره تا اجرا را به صنایع مختلف ارائه می‌دهد.",date:"۱۴۰۴/۰۲/۲۰",cat:"فناوری",img:"https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/blog/iot.jpg"},{slug:"electrical-standards",title:"استانداردهای بین‌المللی تجهیزات برق",excerpt:"آشنایی با مهم‌ترین استانداردهای IEC، NEMA و ISO در حوزه تجهیزات برق صنعتی",content:"رعایت استانداردهای بین‌المللی در صنعت برق تضمین‌کننده کیفیت، ایمنی و قابلیت اطمینان تجهیزات است. مهم‌ترین استانداردهای مورد استفاده در صنعت برق صنعتی عبارتند از:\n\nاستاندارد IEC توسط کمیسیون بین‌المللی الکتروتکنیک منتشر می‌شود و رایج‌ترین استاندارد در اروپا و آسیا است. استاندارد NEMA متعلق به آمریکای شمالی است و تفاوت‌هایی با IEC دارد.\n\nاستاندارد ISO 9001 برای سیستم‌های مدیریت کیفیت و ISO 14001 برای مدیریت زیست محیطی نیز در صنعت تجهیزات برق کاربرد گسترده دارند.",date:"۱۴۰۴/۰۱/۱۰",cat:"استانداردها",img:"https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/blog/standards.jpg"},{slug:"vfd-drives-guide",title:"راهنمای جامع درایوهای فرکانس متغیر",excerpt:"کاربردها، مزایا و نکات مهم در انتخاب درایو VFD مناسب برای صنایع مختلف",content:"درایوهای فرکانس متغیر (VFD) یکی از مهم‌ترین تجهیزات در بهینه‌سازی مصرف انرژی و کنترل دقیق موتورهای الکتریکی هستند. در این مقاله به بررسی انواع VFD و کاربردهای آن می‌پردازیم.\n\nVFDها با کنترل دور موتورهای AC، مصرف انرژی را تا ۵۰٪ کاهش می‌دهند. برندهای معتبر شامل زیمنس، دلتا، ABB و اشنایدر هستند.\n\nانتخاب VFD مناسب به عواملی مانند توان موتور، نوع بار، و شرایط محیطی بستگی دارد.",date:"۱۴۰۳/۱۲/۰۵",cat:"تجهیزات",img:"https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/blog/vfd.jpg"},{slug:"motor-control-centers",title:"تابلوهای MCC و کنترل موتور",excerpt:"اصول طراحی و ساخت تابلوهای کنترل موتور مطابق با استانداردهای بین‌المللی",content:"تابلوهای MCC (Motor Control Center) یکی از اجزای اصلی توزیع برق در صنایع هستند. این تابلوها برای کنترل متمرکز موتورهای الکتریکی طراحی می‌شوند.\n\nMCCها مزایایی مانند کاهش فضای اشغال شده، سهولت تعمیر و نگهداری، افزایش ایمنی و قابلیت مانیتورینگ متمرکز را دارند.\n\nشرکت سورین صنعت فرزان با بهره‌گیری از مهندسان مجرب، انواع تابلوهای MCC را مطابق با استانداردهای IEC 61439 طراحی و تولید می‌کند.",date:"۱۴۰۳/۱۱/۱۵",cat:"تابلو برق",img:"https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/blog/mcc.jpg"},{slug:"power-quality",title:"کیفیت برق و کاهش هارمونیک‌ها",excerpt:"روش‌های بهبود کیفیت توان الکتریکی و کاهش اثرات مخرب هارمونیک‌ها در شبکه",content:"کیفیت برق یکی از چالش‌های اساسی در صنایع مدرن است. هارمونیک‌ها، نوسانات ولتاژ و فلیکر می‌توانند به تجهیزات حساس آسیب برسانند.\n\nراه‌حل‌های بهبود کیفیت برق شامل استفاده از فیلترهای هارمونیک فعال و غیرفعال، UPS، و جبران‌کننده‌های توان راکتیو می‌باشد.\n\nتیم مهندسی ما آماده ارائه مشاوره و اجرای راه‌حل‌های بهبود کیفیت برق در صنایع مختلف است.",date:"۱۴۰۳/۱۰/۲۰",cat:"برق",img:"https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/blog/power-quality.jpg"}]},footer:{desc:"شرکت سورین صنعت فرزان، تامین‌کننده معتبر تجهیزات برق صنعتی، اتوماسیون و ابزار دقیق در ایران و منطقه",rights:"\xa9 ۱۴۰۵ سورین صنعت فرزان. تمامی حقوق محفوظ است.",developer:"توسعه‌دهنده",devName:"محمد مهرانی"},notFound:{title:"صفحه مورد نظر یافت نشد",desc:"متأسفانه صفحه‌ای که به دنبال آن هستید وجود ندارد."},common:{langSwitch:"English",loading:"در حال بارگذاری...",home:"خانه",about:"درباره ما",services:"خدمات",products:"محصولات",blog:"وبلاگ",contact:"تماس",faq:"سوالات"}},en:{site:{title:"Surin Sanat Farzan | Industrial Electrical Equipment",description:"Import and export of industrial electrical equipment, automation, instrumentation"},nav:{logo:"Surin Sanat Farzan",links:[{label:"Home",href:"/"},{label:"About",href:"/about"},{label:"Services",href:"/services"},{label:"Products",href:"/products"},{label:"Blog",href:"/blog"},{label:"Contact",href:"/contact"},{label:"FAQ",href:"/faq"}],contactLabel:"Contact Us"},hero:{name:"Surin Sanat Farzan",subtitle:"Trusted supplier of industrial electrical equipment, automation and instrumentation in Iran and the region",cta:"Free Consultation"},brands:{label:"Brands",title:"Representing Global Brands",items:[{name:"Siemens",img:"/images/brands/siemens.svg"},{name:"Schneider Electric",img:"/images/brands/schneider.svg"},{name:"ABB",img:"/images/brands/abb.svg"},{name:"Delta",img:"/images/brands/delta.svg"},{name:"Omron",img:"/images/brands/omron.svg"},{name:"Mitsubishi",img:"/images/brands/mitsubishi.svg"}]},gallery:{label:"Gallery",title:"Projects & Equipment",items:[{img:"https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/gallery/g1.jpg",title:"HV Switchboard",cat:"Project"},{img:"https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/gallery/g2.jpg",title:"Industrial Control Room",cat:"Project"},{img:"https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/gallery/g3.jpg",title:"Automated Production Line",cat:"Project"},{img:"https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/gallery/g4.jpg",title:"Instrumentation Equipment",cat:"Equipment"},{img:"https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/gallery/g5.jpg",title:"Monitoring System",cat:"Equipment"},{img:"https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/gallery/g6.jpg",title:"Engineering Center",cat:"Office"}]},about:{label:"About Us",title:"Leading Industrial Equipment Supplier",description:"Surin Sanat Farzan with over 7 years of experience in importing and exporting industrial electrical equipment, automation, instrumentation and electrical products is one of the most reliable suppliers in Iran and the region. With a team of 52 specialists, we provide engineering, consulting, design, execution and equipment supply services.",images:["https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/about/office.jpg","https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/about/team.jpg","https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/about/warehouse.jpg","https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/about/project.jpg"],stats:[{value:"7+",label:"Years Experience"},{value:"52+",label:"Specialists"},{value:"98%",label:"Satisfaction"},{value:"12+",label:"Target Countries"}]},services:{label:"Services",title:"Engineering Expertise",items:[{icon:"PenTool",title:"Design, Consulting & Execution",desc:"End-to-end design, technical consulting and execution of electrical and industrial automation projects using the latest global standards"},{icon:"Monitor",title:"Monitoring & Networking",desc:"Design and implementation of monitoring systems, industrial communication networks and centralized production control"},{icon:"Cpu",title:"Parts Support",desc:"Technical proposals for legacy parts, replacement supply and specialized technical consulting"},{icon:"Wrench",title:"Equipment Supply",desc:"Import and supply of industrial electrical equipment, automation, instrumentation and spare parts from world-renowned brands"}]},products:{label:"Products",title:"Products & Equipment",desc:"Supply of industrial electrical equipment, automation, instrumentation and cables from world-renowned brands",items:[{slug:"electrical-equipment",title:"Electrical Equipment",cat:"Switches, Contactors, Fuses, Relays",img:"/images/products/p1.jpg",desc_detail:"Industrial electrical equipment from world-renowned brands including circuit breakers, contactors, fuses, protection relays, current and voltage transformers. All products comply with IEC and NEMA standards and come with valid warranties."},{slug:"industrial-automation",title:"Industrial Automation",cat:"Siemens PLC, Delta, HMI, VFD Drives",img:"/images/products/p2.jpg",desc_detail:"Supply and support of Siemens S7-1200 and S7-1500 PLCs, Delta DVP series PLCs, HMIs, Variable Frequency Drives (VFD), and related software. Programming and commissioning services available."},{slug:"power-plant",title:"Power Plant Equipment",cat:"Generators, UPS, Transformers",img:"/images/products/p3.jpg",desc_detail:"Power plant and industrial electrical equipment including standby diesel generators, UPS systems, distribution and power transformers, and LV/HV switchgear."},{slug:"instrumentation",title:"Instrumentation",cat:"Pressure, Temperature, Flow Meters",img:"/images/products/p4.jpg",desc_detail:"Instrumentation equipment including pressure and temperature transmitters, industrial flow meters, level sensors, gas analyzers, and precision calibrators from leading global brands."},{slug:"industrial-cables",title:"Industrial Cables",cat:"Power, Instrumentation, Network Cables",img:"/images/products/p5.jpg",desc_detail:"Low and medium voltage power cables, instrumentation cables, industrial network cables, and fiber optic cables compliant with international standards."},{slug:"switchboards",title:"Switchboards",cat:"LV & MV Switchboards, Control Panels",img:"/images/products/p6.jpg",desc_detail:"Design and manufacturing of LV and MV switchboards, control and monitoring panels, power distribution boards, and MCC panels according to IEC standards with highest quality."}],cta:"View All Products"},testimonials:{label:"Testimonials",title:"What Our Clients Say",items:[{quote:"Working with Surin Sanat Farzan for automation equipment supply has resulted in excellent quality and on-time delivery.",author:"Eng. Reza Mohammadi",role:"Project Manager",company:"Pars Electrical Industries"},{quote:"Their professional team is very precise and timely in supplying switchboard equipment and instrumentation.",author:"Dr. Samira Ahmadi",role:"Supply Manager",company:"Petro Sanat Shargh"},{quote:"Their technical consulting and parts support services have played an effective role in optimizing our production line.",author:"Eng. Ali Kazemi",role:"Technical Manager",company:"Western Cable Industries"}]},contact:{label:"Contact",title:"Get In Touch",subtitle:"For quotes, expert consultation and collaboration",form:{name:"Full Name",email:"Email",phone:"Phone Number",message:"Your Message",submit:"Send Message",success:"Your message has been sent successfully."},info:{address:"Tehran, Jannatabad Markazi",phone:"+982122201734",email:"info@surinsf.com",hours:"Sat-Wed 8-17 | Thu 8-13"}},faq:{label:"FAQ",title:"Frequently Asked Questions",items:[{q:"Do your products have authenticity guarantees?",a:"Yes, all products come with authenticity guarantees and valid warranties from official representatives."},{q:"What is the delivery time?",a:"In-stock items: 1-3 days. Import orders: 2-6 weeks."},{q:"Do you offer free technical consulting?",a:"Yes, our engineering team provides free technical consulting for your project needs."},{q:"What payment methods are available?",a:"Bank transfer, check, and credit terms for large projects with formal contracts."},{q:"Which brands do you represent?",a:"Siemens, Schneider Electric, ABB, Delta, Omron and many others."}]},blog:{label:"Blog",title:"Latest Articles",desc:"Expert articles on industrial electrical, automation and instrumentation",articles:[{slug:"plc-selection-guide",title:"Complete Guide to Industrial PLC Selection",excerpt:"Review of available PLCs and key selection criteria for your production line",content:"Choosing the right PLC is one of the most critical decisions in industrial automation projects. This article reviews available PLCs from leading brands including Siemens, Delta, ABB and Omron.\n\nKey selection factors include I/O count, communication protocols, environmental conditions, and project budget. Siemens S7-1200 series suits small to medium projects while S7-1500 handles large-scale applications.\n\nDelta Electronics offers cost-effective DVP series PLCs with advanced capabilities.",date:"2025-06-05",cat:"Automation",img:"https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/blog/plc.jpg"},{slug:"industrial-iot",title:"Industrial IoT and Smart Manufacturing",excerpt:"Digital transformation combining traditional automation with IIoT technologies",content:"Industry 4.0 combines traditional industrial automation with the Internet of Things (IoT) to create smart manufacturing environments. IIoT (Industrial Internet of Things) connects machinery, sensors and control systems via network infrastructure.\n\nBenefits include real-time production monitoring, predictive maintenance, energy optimization, and improved Overall Equipment Effectiveness (OEE).\n\nSurin Sanat Farzan provides comprehensive IIoT solutions from consulting to implementation.",date:"2025-05-20",cat:"Technology",img:"https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/blog/iot.jpg"},{slug:"electrical-standards-en",title:"International Electrical Equipment Standards",excerpt:"Overview of IEC, NEMA and ISO standards for industrial electrical equipment",content:"Compliance with international standards ensures quality, safety and reliability in electrical equipment. The most important standards in industrial electrical engineering include:\n\nIEC standards published by the International Electrotechnical Commission are the most common in Europe and Asia. NEMA standards from North America have differences from IEC counterparts.\n\nISO 9001 for quality management and ISO 14001 for environmental management are also widely applied.",date:"2025-04-10",cat:"Standards",img:"https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/blog/standards.jpg"},{slug:"vfd-drives-guide",title:"Complete Guide to Variable Frequency Drives",excerpt:"Applications, benefits and key considerations for selecting the right VFD drive",content:"Variable Frequency Drives (VFD) are essential for optimizing energy consumption and precise motor control. This article covers VFD types and their industrial applications.\n\nVFDs reduce energy consumption by up to 50% by controlling AC motor speed. Leading brands include Siemens, Delta, ABB and Schneider.\n\nSelecting the right VFD depends on motor power, load type, and environmental conditions.",date:"2025-03-05",cat:"Equipment",img:"https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/blog/vfd.jpg"},{slug:"motor-control-centers",title:"MCC Panels and Motor Control",excerpt:"Design principles and construction of motor control centers per international standards",content:"Motor Control Centers (MCC) are essential components of industrial power distribution. These panels are designed for centralized control of electric motors.\n\nMCCs offer benefits including reduced floor space, ease of maintenance, increased safety, and centralized monitoring capabilities.\n\nSurin Sanat Farzan designs and manufactures MCC panels per IEC 61439 standards.",date:"2025-02-15",cat:"Switchboard",img:"https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/blog/mcc.jpg"},{slug:"power-quality",title:"Power Quality and Harmonic Mitigation",excerpt:"Methods for improving power quality and reducing harmful harmonics in electrical networks",content:"Power quality is a critical challenge in modern industries. Harmonics, voltage fluctuations and flicker can damage sensitive equipment.\n\nSolutions include active and passive harmonic filters, UPS systems, and reactive power compensators.\n\nOur engineering team provides consulting and implementation of power quality improvement solutions.",date:"2025-01-20",cat:"Electrical",img:"https://raw.githubusercontent.com/nimamhn/surinsf.com/main/public/images/blog/power-quality.jpg"}]},footer:{desc:"Surin Sanat Farzan, a reliable supplier of industrial electrical equipment, automation and instrumentation in Iran and the region",rights:"\xa9 2025 Surin Sanat Farzan. All rights reserved.",developer:"Developer",devName:"Mohammad Mehrani"},notFound:{title:"Page Not Found",desc:"Sorry, the page you are looking for does not exist."},common:{langSwitch:"فارسی",loading:"Loading...",home:"Home",about:"About",services:"Services",products:"Products",blog:"Blog",contact:"Contact",faq:"FAQ"}}};function o(e){let{children:t}=e,[i,o]=(0,a.useState)("fa"),l=(0,a.useCallback)(e=>{o(e),document.documentElement.lang=e,document.documentElement.dir="fa"===e?"rtl":"ltr"},[]),c=(0,a.useCallback)(()=>l("fa"===i?"en":"fa"),[i,l]);return(0,n.jsx)(s.Provider,{value:{lang:i,t:r[i],setLang:l,toggleLang:c,dir:"fa"===i?"rtl":"ltr"},children:t})}function l(){let e=(0,a.useContext)(s);if(!e)throw Error("useI18n outside LangProvider");return e}}}]);